We can solve this using a **minimum spanning tree** approach, but we can’t explicitly add all edges because the graph would be too large.  

The trick is to add a **virtual node** for each operation, connect all vertices in that operation's subset to it with weight `C_i`, then run Kruskal’s on the resulting smaller graph. That way, the MST weight will count `C_i` for each chosen edge in the original clique.  

Here’s the executable code:  

```python
import sys
sys.setrecursionlimit(1 << 20)

class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return False
        if self.rank[rx] < self.rank[ry]:
            self.parent[rx] = ry
        elif self.rank[rx] > self.rank[ry]:
            self.parent[ry] = rx
        else:
            self.parent[ry] = rx
            self.rank[rx] += 1
        return True

def solve():
    input_data = sys.stdin.read().strip().split()
    it = iter(input_data)
    N = int(next(it))
    M = int(next(it))

    edges = []
    # virtual nodes will have IDs N, N+1, ..., N+M-1
    for op_id in range(M):
        K = int(next(it))
        C = int(next(it))
        vertices = [int(next(it)) - 1 for _ in range(K)]  # 0-based
        virtual_node = N + op_id
        for v in vertices:
            edges.append((C, v, virtual_node))

    # Sort edges by weight
    edges.sort()

    dsu = DSU(N + M)
    total_weight = 0
    edges_used = 0

    for w, u, v in edges:
        if dsu.union(u, v):
            total_weight += w
            edges_used += 1
            if edges_used == N + M - 1:
                break

    # Check connectivity: all N original nodes must be connected
    root_set = set()
    for i in range(N):
        root_set.add(dsu.find(i))
        if len(root_set) > 1:
            break

    if len(root_set) == 1:
        print(total_weight)
    else:
        print(-1)

if __name__ == "__main__":
    solve()
```

