    # For each cell that is 1, the number of right triangles with that cell as the corner
    # is (row_count[i] - 1) * (col_count[j] - 1)
    for i in range(rows):
        for j in range(cols):
            if grid[i][j] == 1:
                total += (row_count[i] - 1) * (col_count[j] - 1)

    return total
