def min_balanced_partitions(s: str) -> int:
    # dp[i] = minimum partitions for s[:i]
    n = len(s)
    dp = [float('inf')] * (n + 1)
    dp[0] = 0

    for i in range(1, n + 1):
        freq = {}
        max_count = 0
        unique_chars = 0
        for j in range(i - 1, -1, -1):
            c = s[j]
            freq[c] = freq.get(c, 0) + 1
            if freq[c] == 1:
                unique_chars += 1
            if freq[c] > max_count:
                max_count = freq[c]

            # Check if substring s[j:i] is balanced
            if max_count * unique_chars == (i - j):
                dp[i] = min(dp[i], dp[j] + 1)

    return dp[n]
