    ]

    total_orders = 0
    good_orders = 0

    for perm in itertools.permutations(range(9)):
        total_orders += 1
        position = {cell: idx for idx, cell in enumerate(perm)}
        disappointed = False

        for a, b, c in lines:
            # Check if first two seen are same number, third different
            if (grid[a] == grid[b] and grid[a] != grid[c]):
                if position[a] < position[c] and position[b] < position[c]:
