def product_matrix(grid):
    MOD = 12345
    n = len(grid)
    m = len(grid[0])

    total_product = 1
    zero_count = 0
    zero_pos = None

    for i in range(n):
        for j in range(m):
            if grid[i][j] % MOD == 0:
                zero_count += 1
                zero_pos = (i, j)
            else:
                total_product = (total_product * (grid[i][j] % MOD)) % MOD

    result = [[0] * m for _ in range(n)]

    if zero_count > 1:
        return result

    if zero_count == 1:
        i, j = zero_pos
        prod = 1
        for r in range(n):
            for c in range(m):
                if (r, c) != (i, j):
                    prod = (prod * (grid[r][c] % MOD)) % MOD
        result[i][j] = prod
        return result

    for i in range(n):
        for j in range(m):
            result[i][j] = (total_product * pow(grid[i][j] % MOD, MOD - 2, MOD)) % MOD

    return result
